mapper.select:
select 'swap' as application_type, se.exchange_id as id, se.duty_id, se.student_id_a as student_id, se.student_name_a as student_name, se.student_id_b as related_student_id, se.student_name_b as related_student_name, se.venue_id, v.venue_name, ds.start_time, ds.end_time, se.exchange_reason as reason, null as proof_image, case se.status when '0' then 'pending' when '3' then 'pending' when '1' then 'approved' when '2' then 'rejected' when '4' then 'cancelled' else se.status end as status, se.status as status_code, se.approve_time, se.approve_remark, se.cancel_time, se.cancel_reason, se.created_at from shift_exchange se left join duty_schedule ds on se.duty_id = ds.duty_id left join venue v on se.venue_id = v.venue_id where se.student_id_a = #{studentId}
and se.status in ('0','3') and se.status = '1' and se.status = '2' and se.status = '4' and se.status = #{status}
order by se.created_at desc

mapper.update:
update shift_exchange
set status = '4',
    cancel_time = #{cancelTime},
    cancel_reason = #{cancelReason},
    updated_at = #{cancelTime}
where exchange_id = #{exchangeId}
  and student_id_a = #{studentId}
  and status in ('0','3')
